module synchronizer(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);

reg [3:0] data_sync_1, data_sync_2;
reg data_en_sync_1, data_en_sync_2;
reg [1:0] data_en_cnt;

always @(posedge clk_a or negedge arstn) begin
    if (~arstn) begin
        data_sync_1 <= 4'b0;
        data_en_sync_1 <= 1'b0;
    end
    else begin
        data_sync_1 <= data_in;
        data_en_sync_1 <= data_en;
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (~brstn) begin
        data_sync_2 <= 4'b0;
        data_en_sync_2 <= 1'b0;
        data_en_cnt <= 2'b0;
    end
    else begin
        data_sync_2 <= data_sync_1;
        data_en_sync_2 <= data_en_sync_1;
        if (data_en_sync_2) begin
            data_en_cnt <= data_en_cnt + 1'b1;
        end
        else begin
            data_en_cnt <= 2'b0;
        end
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (~brstn) begin
        dataout <= 4'b0;
    end
    else begin
        if (data_en_sync_2) begin
            dataout <= data_sync_2;
        end
        else if (data_en_cnt == 2'b11) begin
            dataout <= data_sync_2;
        end
        else begin
            dataout <= 4'b0;
        end
    end
end

endmodule
